# After streaming all audio for the turn:

# 1. Commit the audio buffer
await ws.send(json.dumps({"type": "input_audio_buffer.commit"}))

# 2. Explicitly request a response
await ws.send(json.dumps({
    "type": "response.create",
    "response": {
        "modalities": ["audio", "text"],
        "instructions": "Respond in under 30 words.",  # per-response override
    }
}))

# 3. Cancel the current response if user pushes button again
await ws.send(json.dumps({"type": "response.cancel"}))

# Add tools to session config
SESSION_CONFIG["session"]["tools"] = [
    {
        "type": "function",
        "name": "get_weather",
        "description": "Return current weather for a city.",
        "parameters": {
            "type": "object",
            "properties": {
                "city": {"type": "string", "description": "City name"}
            },
            "required": ["city"]
        }
    }
]
SESSION_CONFIG["session"]["tool_choice"] = "auto"

async def handle_tool_call(ws, call_id: str, fn_name: str, args_json: str):
    args = json.loads(args_json)
    if fn_name == "get_weather":
        result = {"temp_c": 22, "condition": "sunny", "city": args["city"]}

    # Return the function result to the conversation
    await ws.send(json.dumps({
        "type": "conversation.item.create",
        "item": {
            "type": "function_call_output",
            "call_id": call_id,
            "output": json.dumps(result),
        }
    }))
    # Ask the model to continue the response using the tool result
    await ws.send(json.dumps({"type": "response.create"}))

// Browser: capture mic via Web Audio API and send PCM16 to a WebSocket proxy
const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
const ctx = new AudioContext({ sampleRate: 24000 });
const source = ctx.createMediaStreamSource(stream);

// AudioWorklet processes audio in the AudioContext thread
await ctx.audioWorklet.addModule('/pcm-processor.js');
const node = new AudioWorkletNode(ctx, 'pcm-processor');
source.connect(node);

const ws = new WebSocket('wss://your-server.com/realtime-proxy');
ws.binaryType = 'arraybuffer';

// Forward PCM chunks from worklet to proxy WebSocket
node.port.onmessage = ({ data }) => {
  if (ws.readyState === WebSocket.OPEN) ws.send(data);
};

// Play back audio chunks received from the proxy
ws.onmessage = async ({ data }) => {
  const pcm = new Int16Array(data);
  const float32 = Float32Array.from(pcm, s => s / 32768.0);
  const buf = ctx.createBuffer(1, float32.length, 24000);
  buf.copyToChannel(float32, 0);
  const src = ctx.createBufferSource();
  src.buffer = buf;
  src.connect(ctx.destination);
  src.start();
};

# Twilio sends mulaw 8kHz; configure the Realtime session to match
TELEPHONY_SESSION = {
    "type": "session.update",
    "session": {
        "input_audio_format": "g711_ulaw",
        "output_audio_format": "g711_ulaw",
        "voice": "alloy",
        "modalities": ["audio", "text"],
        "instructions": "You are a phone agent. Keep answers short.",
        "turn_detection": {
            "type": "server_vad",
            "silence_duration_ms": 700,  # phone callers need longer pause
        }
    }
}

# Twilio Media Stream WebSocket → forward to OpenAI without transcoding
async def forward_twilio_to_openai(twilio_ws, openai_ws):
    async for message in twilio_ws:
        event = json.loads(message)
        if event["event"] == "media":
            # Twilio payload is base64 mulaw — forward directly
            await openai_ws.send(json.dumps({
                "type": "input_audio_buffer.append",
                "audio": event["media"]["payload"],
            }))
